						? isEditing
							? "Updating..."
							: "Creating..."
						: isEditing
							? "Update Column"
							: "Create Column"}
				</Button>
				<Button
					type="button"
					variant="outline"
					onClick={onClose}
					disabled={isPending}
				>
					Cancel
				</Button>
			</div>
		</form>
	);
}

"use client";

import { useState } from "react";
import { Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { MinimalTiptapEditor } from "@/components/ui/minimal-tiptap";
import SearchSelect from "@/components/ui/search-select";
import { useTaskMutations, useSearchUsers } from "@btst/stack/plugins/kanban/client/hooks";
import { PRIORITY_OPTIONS } from "../../../utils";
import type {
	SerializedColumn,
	SerializedTask,
	Priority,
} from "../../../types";

interface TaskFormProps {
	columnId: string;
	boardId: string;
	taskId?: string;
	task?: SerializedTask;
	columns: SerializedColumn[];
	onClose: () => void;
	onSuccess: () => void;
	onDelete?: () => void;
}

export function TaskForm({
	columnId,
	boardId,
	taskId,
	task,
	columns,
	onClose,
	onSuccess,
	onDelete,
}: TaskFormProps) {
	const isEditing = !!taskId;
	const {
		createTask,
		updateTask,
		moveTask,
		isCreating,
		isUpdating,
		isDeleting,
		isMoving,
	} = useTaskMutations();

	const [title, setTitle] = useState(task?.title || "");
	const [description, setDescription] = useState(task?.description || "");
	const [priority, setPriority] = useState<Priority>(
		task?.priority || "MEDIUM",
	);
	const [selectedColumnId, setSelectedColumnId] = useState(
		task?.columnId || columnId,
	);
	const [assigneeId, setAssigneeId] = useState<string>(task?.assigneeId || "");
	const [error, setError] = useState<string | null>(null);

	// Fetch available users for assignment
	const { data: users = [] } = useSearchUsers("", boardId);
	const userOptions = [
		{ value: "", label: "Unassigned" },
		...users.map((user) => ({ value: user.id, label: user.name })),
	];

	const isPending = isCreating || isUpdating || isDeleting || isMoving;

	const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
		e.preventDefault();
		setError(null);

		if (!title.trim()) {
			setError("Title is required");
			return;
		}

		try {
			if (isEditing && taskId) {
				const isColumnChanging =
					task?.columnId && selectedColumnId !== task.columnId;

				if (isColumnChanging) {
					// When changing columns, we need two operations:
					// 1. Update task properties (title, description, priority, assigneeId)
					// 2. Move task to new column with proper order calculation
					//
					// To avoid partial failure confusion, we attempt both operations
					// but provide clear messaging if one succeeds and the other fails.

					// First update the task properties (title, description, priority, assigneeId)
					// If this fails, nothing is saved and the outer catch handles it
					await updateTask(taskId, {
						title,
						description,
						priority,
						assigneeId: assigneeId || null,
					});

					// Then move the task to the new column with calculated order
					// Place at the end of the destination column
					try {
						const targetColumn = columns.find((c) => c.id === selectedColumnId);
						const targetTasks = targetColumn?.tasks || [];
						const targetOrder =
							targetTasks.length > 0
								? Math.max(...targetTasks.map((t) => t.order)) + 1
								: 0;

						await moveTask(taskId, selectedColumnId, targetOrder);
					} catch (moveErr) {
						// Properties were saved but column move failed
						// Provide specific error message about partial success
						const moveErrorMsg =
							moveErr instanceof Error ? moveErr.message : "Unknown error";
						setError(
							`Task properties were saved, but moving to the new column failed: ${moveErrorMsg}. ` +
								`You can try dragging the task to the desired column.`,
						);
						// Don't call onSuccess since the operation wasn't fully completed
						// but also don't throw - we want to show the specific error
						return;
					}
				} else {
					// Same column - just update the task properties
					await updateTask(taskId, {
						title,
						description,
						priority,
						columnId: selectedColumnId,
						assigneeId: assigneeId || null,
					});
				}
			} else {
				await createTask({
					title,
					description,
					priority,
					columnId: selectedColumnId,
					assigneeId: assigneeId || undefined,
				});
			}
			onSuccess();
		} catch (err) {
			setError(err instanceof Error ? err.message : "An error occurred");
		}
	};

	return (
		<form onSubmit={handleSubmit} className="space-y-4">
			<div className="space-y-2">
				<Label htmlFor="title">Title *</Label>
				<Input
					id="title"
					value={title}
					onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
						setTitle(e.target.value)
					}
					placeholder="e.g., Fix login bug"
					disabled={isPending}
				/>
			</div>

			<div className="grid grid-cols-2 gap-4">
				<div className="space-y-2">
					<Label htmlFor="priority">Priority</Label>
					<Select
						value={priority}
						onValueChange={(v: string) => setPriority(v as Priority)}
					>
						<SelectTrigger>
							<SelectValue placeholder="Select priority" />
						</SelectTrigger>
						<SelectContent>
							{PRIORITY_OPTIONS.map((option) => (
								<SelectItem key={option.value} value={option.value}>
									{option.label}
								</SelectItem>
							))}
						</SelectContent>
					</Select>
				</div>

				<div className="space-y-2">
					<Label htmlFor="column">Column</Label>
					<Select value={selectedColumnId} onValueChange={setSelectedColumnId}>
						<SelectTrigger>
							<SelectValue placeholder="Select column" />
						</SelectTrigger>
						<SelectContent>
							{columns.map((col) => (
								<SelectItem key={col.id} value={col.id}>
									{col.title}
								</SelectItem>
							))}
						</SelectContent>
					</Select>
				</div>
			</div>

			<div className="space-y-2">
				<Label htmlFor="assignee">Assignee</Label>
				<SearchSelect
					options={userOptions}
					value={assigneeId}
					onChange={setAssigneeId}
					placeholder="Select assignee"
					emptyMessage="No users found"
				/>
			</div>

			<div className="space-y-2">
				<Label>Description</Label>
				<MinimalTiptapEditor
					value={description}
					onChange={(value) =>
						setDescription(typeof value === "string" ? value : "")
					}
					output="markdown"
					placeholder="Describe the task..."
					editable={!isPending}
					className="min-h-[150px]"
				/>
			</div>

			{error && (
				<div className="p-3 text-sm text-red-600 bg-red-50 border border-red-200 rounded-md">
					{error}
				</div>
			)}

			<div className="flex justify-between pt-2">
				<div className="flex gap-2">
					<Button type="submit" disabled={isPending}>
						{isPending
							? isEditing
								? "Updating..."
								: "Creating..."
							: isEditing
								? "Update Task"
								: "Create Task"}
					</Button>
					<Button
						type="button"
						variant="outline"
						onClick={onClose}
						disabled={isPending}
					>
						Cancel
					</Button>
				</div>
				{isEditing && onDelete && (
					<Button
						type="button"
						variant="destructive"
						onClick={onDelete}
						disabled={isPending}
					>
						<Trash2 className="mr-2 h-4 w-4" />
						Delete
					</Button>
				)}
			</div>
		</form>
	);
}

"use client";

import { Skeleton } from "@/components/ui/skeleton";
import { Card, CardContent, CardHeader } from "@/components/ui/card";

export function BoardsListSkeleton() {
	return (
		<div className="container mx-auto py-8 px-4">
			<div className="w-full flex items-center justify-between mb-8">
				<div>
					<Skeleton className="h-9 w-48" />
					<Skeleton className="h-5 w-64 mt-2" />
				</div>
				<Skeleton className="h-10 w-32" />
			</div>
			<div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
				{Array.from({ length: 6 }).map((_, i) => (
