											{board.description}
										</CardDescription>
									)}
								</CardHeader>
								<CardContent>
									<div className="flex items-center justify-between text-sm text-muted-foreground">
										<span>{board.columns?.length || 0} columns</span>
										<span>
											{format(new Date(board.createdAt), "MMM d, yyyy")}
										</span>
									</div>
								</CardContent>
							</Card>
						</Link>
					))}
				</div>
			) : (
