		usePluginOverrides<KanbanPluginOverrides>("kanban");
	const navigate =
		overrideNavigate ||
		((path: string) => {
			window.location.href = path;
		});
	const Link = OverrideLink || "a";

	const handleSuccess = (boardId: string) => {
		navigate(`/pages/kanban/${boardId}`);
